INSERT INTO shopjoy_2604.sy_template (template_id, site_id, template_type_cd, template_code, template_nm, template_subject, template_content, sample_params, use_yn, disp_path, reg_by, reg_date) VALUES ('TP000100', 'SITE000001', 'EMAIL', 'BO_TEMPORARY_PASSWORD', 'BO 임시비밀번호 발급', 'BO_임시비밀번호 발급', '<title>임시비밀번호 발급</title> 	<div style="margin: 0px auto; width: 590px; color: rgb(102, 102, 102); line-height: 1.2; letter-spacing: -0.05em; font-family:;" 맑은="" 고딕",malgun="" gothic;="" 12px;"=""> 		<!-- logo --> 		<div style="margin: 60px 0px 35px; line-height: 0; padding-left: 30px; font-size: 0px; vertical-align: top;"> 			<a title="ShopJoy" href="http://www.idlookmall.com" target="_blank"><img style="border: 0px currentColor; border-image: none;" alt="idlookmall.com" src="http://img.idlookmall.com/IDLOOKEMAILTEMPLATE/mail_logo.png"></a> 		</div> 		 		<!-- 메시지영역 --> 		<div style="margin: 0px; padding: 80px 0px 70px; text-align: center; border-top-color: rgb(0, 0, 0); border-bottom-color: rgb(221, 221, 221); border-top-width: 1px; border-bottom-width: 1px; border-top-style: solid; border-bottom-style: solid;"> 			<!-- 아이콘영역 --> 			<div style="line-height: 0; font-size: 0px; vertical-align: top;"> 				<img style="border: 0px currentColor; border-image: none;" alt="" src="http://img.idlookmall.com/IDLOOKEMAILTEMPLATE/icon02.png"> 			</div> 			 			<!-- 메인텍스트--> 			<p style="margin: 30px 0px 0px; padding: 0px; color: rgb(0, 0, 0); letter-spacing: -1px; font-size: 30px;"> 				임시 비밀번호가 발급되었습니다. 			</p> 			 			<!-- 서브텍스트--> 			<p style="margin: 40px 0px 0px; padding: 0px 50px; text-align: left; line-height: 21px; letter-spacing: -0.05em; font-size: 13px;"> 				안녕하세요. <strong>[[${memNm}]]</strong>님<br><br> 				고객님께서 요청하신 임시 비밀번호를 발송해 드립니다.<br> 				임시 비밀번호로 로그인하신 후 <span style="color: rgb(102, 102, 102); font-weight: bold; text-decoration: none;">[마이페이지 &gt; 개인정보관리 &gt; 비밀번호 변경]</span>에서 <br> 				비밀번호를 꼭 변경하여 이용하시기 바랍니다. 			</p> 		</div> 		<!-- //메시지영역 --> 	 		<div style="padding: 35px 0px; border: 1px solid rgb(221, 221, 221); border-image: none; text-align: center;"> 			<p style="margin: 0px; padding: 0px; font-size: 20px;"> 				<span style="width: 120px; text-align: left; display: inline-block;">임시비밀번호</span> 				<strong style="color: rgb(125, 81, 218); font-weight: bold; margin-left: 30px; display: inline-block;">[[${temporaryPassword}]]</strong> 			</p> 		</div> 		<!-- 버튼영역 --> 		<div style="margin: 50px 0px 0px; padding: 0px; text-align: center;"> <a style="padding: 20px 50px; text-align: center; color: rgb(255, 255, 255); font-size: 14px; font-weight: bold; text-decoration: none; display: inline-block; background-color: rgb(0, 0, 0);" href="http://www.idlookmall.com/login" target="_blank">ShopJoy 로그인하기</a> 		</div> 		<!-- //버튼영역 --> 		<!-- 푸터영역 --> 		<div style="padding: 25px 20px; color: rgb(153, 153, 153); line-height: 21px; margin-top: 70px; background-color: rgb(245, 245, 245);"> 			<p style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); line-height: 21px;">- 본 메일은 발신 전용 메일로 회신되지 않습니다.</p> 			<p style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); line-height: 21px;">- 문의사항은 고객센터의 <a style="color: rgb(0, 0, 0); text-decoration: underline;" href="http://www.idlookmall.com/csCenter/faqMainList" target="_blank">자주 묻는 질문</a> 또는 <a style="color: rgb(0, 0, 0); text-decoration: underline;" href="http://www.idlookmall.com/csCenter/customerCenter" target="_blank">1:1 온라인 상담</a>을 이용해 주십시오.</p> 			 			<p style="margin: 30px 0px 0px; padding: 0px;">㈜ShopJoy | 대표이사 :&nbsp;김재풍&nbsp; | 사업자등록번호 : 211-81-39521</p> 			<p style="margin: 0px; padding: 0px;">통신판매업신고 : 서울 강남 02143호 <a style="color: rgb(0, 0, 0); text-decoration: underline;" href="http://www.ftc.go.kr/info/bizinfo/communicationView.jsp?apv_perm_no=2009322012730202143&amp;area1=&amp;area2=&amp;currpage=1&amp;searchKey=04&amp;searchVal=2118139521&amp;stdate=&amp;enddate= " target="_blank">사업자정보확인</a> | 개인정보 책임 관리자 : <span style="letter-spacing: -0.05em;"></span><span style="letter-spacing: normal;">문무홍</span></p><p style="margin: 0px; padding: 0px;"><span style="letter-spacing: -0.05em;">서울특별시 강남구 강남대로 580 성보빌딩 8층 | 물류센터 : 경기도 평택시 서탄면 서탄 2로 97</span></p> 			<p style="margin: 0px; padding: 0px;">고객지원실 : TEL. 1833-2250 | FAX 02-547-8329</p> 		</div> 		<!-- //푸터영역 --> 	</div><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p><br></p>', '{"memNm":"{memNm}","temporaryPassword":"{temporaryPassword}"}', 'Y', '회원.이메일', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT (template_type_cd, template_code) DO UPDATE SET template_subject = EXCLUDED.template_subject, template_content = EXCLUDED.template_content, sample_params = EXCLUDED.sample_params, upd_by = 'SYSTEM', upd_date = '2026-04-20 00:00:00';
