INSERT INTO shopjoy_2604.sy_template (template_id, site_id, template_type_cd, template_code, template_nm, template_subject, template_content, sample_params, use_yn, disp_path, reg_by, reg_date) VALUES ('TP000102', 'SITE000001', 'EMAIL', 'BIRTHDAY_BNFT', '생일 축하 혜택 지급', '[ShopJoy] 생일축하 혜택 지급', '<title>생일 축하 메일</title> <div style="margin: 0px auto; width: 590px; color: rgb(102, 102, 102); line-height: 1.3; letter-spacing: -0.05em; font-family:;" 12px;"="" gothic;="" 고딕",malgun="" 맑은=""> 	<!-- logo --> 	<div style="margin: 60px 0px 35px; line-height: 0; padding-left: 30px; font-size: 0px; vertical-align: top;"> 		<a title="ShopJoy" href="http://www.idlookmall.com" target="_blank"><img style="border: 0px currentColor; border-image: none;" alt="idlookmall.com" src="http://img.idlookmall.com/IDLOOKEMAILTEMPLATE/mail_logo.png"></a> 	</div> 	 	<!-- 메시지영역 --> 	<div style="margin: 0px; padding: 80px 0px 70px; text-align: center; border-top-color: rgb(0, 0, 0); border-top-width: 1px; border-top-style: solid;"> 		<!-- 아이콘영역 --> 		<div style="line-height: 0; font-size: 0px; vertical-align: top;"> 			<img style="border: 0px currentColor; border-image: none;" alt="" src="http://img.idlookmall.com/IDLOOKEMAILTEMPLATE/icon03.png"> 		</div> 		 		<!-- 메인텍스트--> 		<p style="margin: 30px 0px 0px; padding: 0px; color: rgb(0, 0, 0); letter-spacing: -1px; font-size: 30px;"> 			고객님의 생일을 진심으로 <br>축하 드립니다. 		</p> 		 		<!-- 서브텍스트--> 		<p style="margin: 40px 0px 0px; padding: 0px 50px; text-align: left; line-height: 21px; letter-spacing: -0.05em; font-size: 13px;"> 			특별한 날, 행복한 날, <strong>[[${memNm}]]</strong> 님의 생일을 진심으로 축하 드립니다. <br> 			<strong style="color: rgb(125, 81, 218); font-weight: bold;">[[${birthDay}]]</strong> 고객님의 특별한 날을 기념하는 선물로 생일 축하 쿠폰을 발급해 드립니다.<br><br> 			언제나 즐겁고 편리한 쇼핑을 하실 수 있도록 최선을 다하는 ShopJoy이 되겠습니다. 		</p> 	</div> 	<!-- //메시지영역 --> 	<!-- 쿠폰 	<div style="height: 152px; padding: 28px 50px 40px; border: 1px solid rgb(242, 242, 242); border-image: none; overflow: hidden; clear