x;">㈜ShopJoy | 대표이사 : 김재풍 | 사업자등록번호 : 211-81-39521</p> 		<p style="margin: 0px; padding: 0px;">통신판매업신고 : 서울 강남 02143호 <a style="color: rgb(0, 0, 0); text-decoration: underline;" href="http://www.ftc.go.kr/info/bizinfo/communicationView.jsp?apv_perm_no=2009322012730202143&amp;area1=&amp;area2=&amp;currpage=1&amp;searchKey=04&amp;searchVal=2118139521&amp;stdate=&amp;enddate= " target="_blank">사업자정보확인</a> | 개인정보 책임 관리자 : <span style="letter-spacing: -0.05em;">문무홍</span></p><p style="margin: 0px; padding: 0px;"><span style="letter-spacing: -0.05em;">서울특별시 강남구 강남대로 580 성보빌딩 8층 | 물류센터 : 경기도 평택시 서탄면 서탄 2로 97</span></p> 		<p style="margin: 0px; padding: 0px;">고객지원실 : TEL. 1833-2250 | FAX 02-547-8329</p> 	</div> 	<!-- //푸터영역 --> </div><p>&nbsp;</p>', '{"memNm":"{memNm}","birthDay":"{birthDay}","cpnNm":"{cpnNm}","bnftAmt":"{bnftAmt}","maxBnftAmt":"{maxBnftAmt}","useStrDttm":"{useStrDttm}","useEndDttm":"{useEndDttm}","saveNm":"{saveNm}","saveVal":"{saveVal}","saveUseStrDttm":"{saveUseStrDttm}","saveUseEndDttm":"{saveUseEndDttm}"}', 'Y', '프로모션.이메일', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT (template_type_cd, template_code) DO UPDATE SET template_subject = EXCLUDED.template_subject, template_content = EXCLUDED.template_content, sample_params = EXCLUDED.sample_params, upd_by = 'SYSTEM', upd_date = '2026-04-20 00:00:00';
INSERT INTO shopjoy_2604.sy_template (template_id, site_id, template_type_cd, template_code, template_nm, template_subject, template_content, sample_params, use_yn, disp_path, reg_by, reg_date) VALUES ('TP000103', 'SITE000001', 'EMAIL', 'ORD_COMPLETE', '주문완료', '[ShopJoy] 주문이 완료되었습니다.', '<!DOCTYPE html> <html lang="ko"> <head> 	<meta charset="UTF-8"> 	<meta http-equiv="Content-Script-Type" content="text/javascript"> 	<meta http-equiv="Content-Style-Type" content="text/css"> 	<meta http-equiv="X-UA-Compatible" content="IE=edge"> 	<title>주문완료</title> </head> <body style="margin: 0;padding: 0"> 	 <div style="margin: 0px auto; width: 590px; color: rgb(102, 102, 102); line-height: 1.2; letter-spacing: -0.05em; font-family: " 맑은="" 고딕",malgun="" gothic;="" font-size:="" 12px;"=""> 	<!-- logo --> 	<div style="margin: 60px 0px 35px; line-height: 0; padding-left: 30px; font-size: 0px; vertical-align: top;"> 		<a title="ShopJoy" href="https://www.idlookmall.com" target="_blank"><img style="border: 0px currentColor; border-image: none;" alt="idlookmall.com" src="https://img.idlookmall.com/IDLOOKEMAILTEMPLATE/mail_logo.png"></a> 	</div> 	<!-- 메시지영역 --> 	<div style="margin: 0px; padding: 80px 0px 70px; text-align: center; border-top-color: rgb(0, 0, 0); border-bottom-color: rgb(221, 221, 221); border-top-width: 1px; border-bottom-width: 1px; border-top-style: solid; border-bottom-style: solid;"> 		<!-- 아이콘영역 --> 		<div style="line-height: 0; font-size: 0px; vertical-align: top;"> 			<img style="border: 0px currentColor; border-image: none;" alt="" src="https://img.idlookmall.com/IDLOOKEMAILTEMPLATE/icon06.png"> 		</div> 		 		<!-- 메인텍스트--> 		<p style="margin: 30px 0px 0px; padding: 0px; color: rgb(0, 0, 0); letter-spacing: -1px; font-size: 30px;"> 			주문이 완료 되었습니다. 		</p> 		<p style="margin: 15px 0px 0px; padding: 0px; color: rgb(102, 102, 102); font-size: 15px;">“ShopJoy을 이용해 주셔서 감사합니다.”</p> 	</div> 	<!-- //메시지영역 --> 	<!-- 주문내역 --> 	<div style="margin: 30px 0px 0px; padding: 0px;"> 		<p style="margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-size: 13px;"> 			<strong style="width: 115px; display: inline-block;">주문번호</strong><strong style="color: rgb(125, 81, 218);">[[${ordNo}]]</strong> 		</p> 		<p style="margin: 20px 0px 0px; padding: 0px; color: rgb(0, 0, 0); font-size: 13px;"> 			<strong style="width: 115px; display: inline-block;">주문일시</strong><span>[[${ordDttm}]]</span> 		</p> 		<p style="margin: 20px 0px 0px; padding: 0px; color: rgb(0, 0, 0); font-size: 13px;"> 			<strong style="width: 115px; display: inline-block;">주문상품</strong><span>[[${prdNm}]]</span> 		</p> 		<!-- 결제수단/결제내역/적립금 --> 		<table style="width: 100%; margin-top: 30px; border-top-color: rgb(0, 0, 0); border-top-width: 1px; border-top-style: solid; border-collapse: collapse; border-spacing: 0;"> 			<caption style="display: none;">주문내역</caption> 			<colgroup> 				<col style="width: 40%;"> 				<col style="width: 60%;"> 			</colgroup> 			<!-- 결제 --> 			<tbody> 				<tr> 					<th style="padding: 30px 0px; text-align: left; color: rgb(0, 0, 0); font-size: 15px; vertical-align: top; border-bottom-color: rgb(242, 242, 242); border-bottom-width: 1px; border-bottom-style: solid;" scope="row">결제수단</th> 					<td style="padding: 30px 0px; text-align: right; font-size: 13px; border-bottom-color: rgb(242, 242, 242); border-bottom-width: 1px; border-bottom-style: solid;"> 						<div style="margin: 0px; padding: 0px; width: 330px; height: 100%; color: rgb(0, 0, 0); overflow: hidden; display: inline-block; position: relative;"> 						[[${payMthdNm}]] 						</div> 					</td> 				</tr>	 				<tr> 					<th style="padding: 30px 0px; text-align: left; color: rgb(0, 0, 0); font-size: 15px; vertical-align: top; border-bottom-color: rgb(221, 221, 221); border-bottom-width: 1px; border-bottom-style: solid;" scope="row"> 						결제내역 					</th> 					<td style="padding: 30px 0px; text-align: right; font-size: 13px; vertical-align: top; border-bottom-color: rgb(221, 221, 221); border-bottom-width: 1px; border-bottom-style: solid;"> 						<div style="margin: 0px; padding: 0px; width: 330px; height: 100%; color: rgb(0, 0, 0); overflow: hidden; display: inline-block; position: relative;"> 							<div style="width: 130px; height: 18px; text-align: left; clear: both; float: left;"> 								상품금액 							</div> 							<div style="height: 18px; text-align: right; float: right;"> 								<span>[[${selPrc}]]</span>원 							</div> 							 							<div style="width: 130px; height: 21px; text-align: left; clear: both; margin-top: 10px; float: left;"> 								상품할인 							</div> 							<div style="height: 21px; text-align: right; margin-top: 10px; float: right;"> 								<span style="color: rgb(232, 78, 78);">-[[${dscAmt}]]</span>원 							</div> 							 							<div style="width: 130px; height: 21px; text-align: left; clear: both; margin-top: 10px; float: left;"> 								쿠폰할인 							</div> 							<div style="height: 21px; text-align: right; margin-top: 10px; float: right;"> 								<span style="color: rgb(232, 78, 78);">-[[${dscCpnAmt}]]</span>원 							</div> 							 							<div style="width: 130px; height: 21px; text-align: left; clear: both; margin-top: 10px; float: left;"> 								배송비 							</div> 							<div style="height: 21px; text-align: right; margin-top: 10px; float: right;"> 								<span>[[${dlvAmt}]]</span>원 							</div> 							 							<div style="width: 130px; height: 21px; text-align: left; clear: both; margin-top: 10px; float: left;"> 								마일리지사용 							</div> 							<div style="height: 21px; text-align: right; margin-top: 10px; float: right;"> 								<span style="color: rgb(232, 78, 78);">-[[${saveAmt}]]</span>M 							</div> 							<div style="width: 130px; height: 18px; text-align: left; clear: both; margin-top: 10px; float: left;"> 								지급예정마일리지 							</div> 							<div style="height: 18px; text-align: right; margin-top: 10px; float: right;"> 								<span>[[${realSaveAmt}]]</span>M 							</div> 						</div> 					</td> 				</tr> 				<tr> 					<th styl